import { BottomSheetPopup } from "@/types/ui/BottomSheetPopup.js";
import { Button } from "@/types/ui/Button.js";
import { Table } from "@/types/ui/Table.js";
import { Input } from "@/types/ui/Input.js";

export default function () {
  const { t } = useI18n();

  // 거래처별 검수 목록 팝업
  const customerInspectionBottomSheet = ref(
    new BottomSheetPopup.Builder()
      .setPopupId("customerInspectionListPopup")
      .setPopupName("customerInspectionListPopup")
      .setTitle("거래처명")
      .setPopupType("check")
      .setShowButton(false)
      .setPopupState(false)
      .build()
  );

  // 일괄전송 버튼
  const pharmaInspectionSendBtn = ref(
    new Button.Builder()
      .setBtnStyle("grid-8")
      .setBtnText(computed(() => t("buttonLabel.sendAll")))
      .build()
  );

  // 거래처명 버튼
  const customerInfoBtn = ref(new Button.Builder().setBtnStyle("btn--customer").build());

  // 상차검수 테이블
  const pharmaQuickupScanList = ref(
    new Table.Builder()
      .setColumnName(["거래처", "박스수", "검수", "미검수"])
      .setColumnsKey(["agntName", "boxCount", "inspected", "uninspected"])
      .setRows()
      .setCheckBox(true)
      .setTotal(true)
      .setIncorrectScan(true)
      .setTxtColorRed([false, false, false, true])
      .settdType([[true, "btn", customerInfoBtn.value], false])
      .build()
  );
  // 거래처 상세 테이블
  const agntProductDetailList = ref(
    new Table.Builder()
      .setColumnName(["바코드", "아이템", "상태"])
      .setColumnsKey(["barcode", "productName", "scanState"])
      .setRows()
      .setAlignLeft([false, true, false])
      .setCheckBox(false)
      .build()
  );

  // 검색창 입력란
  const carNumSearchInput = ref(
    new Input.Builder()
      .setType("search")
      .setInputStyle("carNumSearchInput")
      .setInputName("carNumSearchInput")
      .setLabelName("carNumSearchInput")
      .setPlaceholder("차량번호를 입력해주세요")
      .setReadOnly(false)
      .setInputMode("search")
      .setScanYN(false)
      .build()
  );

  return {
    customerInspectionBottomSheet,
    pharmaInspectionSendBtn,
    pharmaQuickupScanList,
    agntProductDetailList,
    customerInfoBtn,
    carNumSearchInput,
  };
}

