import pharmaInspectionCommonObject from "@/objects/page/inspection/pharmaInspectionCommonObject.js";
import ScanType from "@/const/ScanType";
import audio from "@/common/audio.js";
import commonInspectionComposable from "@/composables/main/inspection/commonInspection.js";
import isEmpty from "lodash/isEmpty";

export const SIMPLE_INSPECTION_MODE = Object.freeze({
  LOADING: "loading",
  CANCEL: "cancel",
});

const SCAN_STATE_REJECT = "REJECT";

export default function (inspectionSendAction, modeOptions = {}) {
  const { playSuccessSound, playFailSound, playDuplicationSound } = audio();
  const {
    customerInspectionBottomSheet,
    pharmaInspectionSendBtn,
    pharmaQuickupScanList,
    agntProductDetailList,
    cancelScanList,
    customerInfoBtn,
    carNumSearchInput,
  } = pharmaInspectionCommonObject();

  const {
    stopName,
    upScanList,
    selectedItem,
    scannerState,
    scannerStateText,
    countData,
    registeredToastPopup,
    storeScanAlert,
    storeScanGuideYn,
    scanType,
    misScanned,
    setScanTypeDevice,
    setScanTypeManual,
    clearScanType,
    scannerContect,
    storeScanAlertCloseAction,
    storeScanAlertAction,
    setSelectedItem,
    updateMisScannedCount,
    getScannedBarcode,
  } = commonInspectionComposable();
  const needToFilter = ref(false);
  let agntAllProductList = [];
  let originScanBarcodeList = [];

  function getModeOptionValue() {
    const modeSource = modeOptions?.mode ?? modeOptions;
    return modeSource?.value ?? modeSource;
  }

  const inspectionMode = computed(() => {
    const modeValue = getModeOptionValue();
    return modeValue === SIMPLE_INSPECTION_MODE.CANCEL
      ? SIMPLE_INSPECTION_MODE.CANCEL
      : SIMPLE_INSPECTION_MODE.LOADING;
  });

  const isCancelMode = () => inspectionMode.value === SIMPLE_INSPECTION_MODE.CANCEL;

  function isRejectedItem(item) {
    return item.scanStateCode === SCAN_STATE_REJECT;
  }

  function isScannedItem(item) {
    return !isEmpty(item.scanDate);
  }

  function isLoadingSelectableItem(item) {
    return !isScannedItem(item) && !isRejectedItem(item);
  }

  function isCancelSelectableItem(item) {
    return isScannedItem(item) && !isRejectedItem(item);
  }

  function isSelectableItem(item) {
    return isCancelMode() ? isCancelSelectableItem(item) : isLoadingSelectableItem(item);
  }

  function isSelectableScanTarget(item) {
    return !item.checked && isSelectableItem(item);
  }

  function isSameGroup(row, item) {
    if (!row || row.stopCode != item.stopCode) {
      return false;
    }

    return !row.loadKey || row.loadKey == item.loadKey;
  }

  function getGroupItems(row) {
    return agntAllProductList.filter((item) => isSameGroup(row, item));
  }

  function hasCancelableGroupItems(row) {
    if (agntAllProductList.length === 0) {
      return Number(row.inspected) > 0;
    }

    return getGroupItems(row).some((item) => isCancelSelectableItem(item));
  }

  function getRowFinished(row) {
    if (isCancelMode() && hasCancelableGroupItems(row)) {
      return false;
    }

    return row.loadingFinished;
  }

  function clearCheckedState() {
    agntAllProductList.forEach((item) => {
      item.checked = false;
      clearScanType(item);
    });
    originScanBarcodeList.forEach((item) => {
      item.checked = false;
    });
    (upScanList.value.rows || []).forEach((item) => {
      item.checked = false;
    });
    misScanned.value.length = 0;
  }

  function refreshRowSelectability() {
    originScanBarcodeList.forEach((item) => {
      item.finished = getRowFinished(item);
    });
    originScanBarcodeList.sort((a, b) => {
      return a.finished === b.finished ? 0 : a.finished ? 1 : -1;
    });
  }

  function syncRowCheckedState(row) {
    if (!row) {
      return;
    }

    const selectableGroupItems = getGroupItems(row).filter((item) => isSelectableItem(item));
    row.checked =
      selectableGroupItems.length > 0 && selectableGroupItems.every((item) => item.checked);
  }

  function getCancelScannedBarcode(item) {
    return {
      BARCODE_NO: item.barcode,
      LOAD_KEY: item.loadKey,
      AGNT_CODE: item.agentCode,
    };
  }

  function getSubmitBarcode(item) {
    return isCancelMode() ? getCancelScannedBarcode(item) : getScannedBarcode(item);
  }

  watch(inspectionMode, () => {
    clearCheckedState();
    refreshRowSelectability();
    filterScanBarcodeList(carNumSearchInput.value.inputValue);
  });

  function updateBarcodeCheck(barcode) {
    if (barcode && agntAllProductList.length > 0) {
      const row = agntAllProductList.find(
        (item) => item.barcode == barcode && isSelectableScanTarget(item)
      );
      if (row) {
        row.checked = true;
        setScanTypeDevice(row);
        inspectionSendAction();
        playSuccessSound();
      } else if (agntAllProductList.some((item) => item.barcode == barcode)) {
        playDuplicationSound();
      } else {
        updateMisScannedCount(barcode);
        playFailSound();
      }
    }
  }

  function onNativeBarcodeDetect(data) {
    if (scanType.value !== ScanType.NOT_INSPECTION) {
      updateBarcodeCheck(data.barcode);
    }
  }

  function onBarcodeDetectByCamera(data) {
    const barcodeInfo = M.navigator.os("ios") ? JSON.parse(data) : data;
    barcodeInfo.barcodeItemList.forEach((newData) => {
      const item = agntAllProductList.find(
        (oldData) => oldData.barcode === newData.barcode && isSelectableScanTarget(oldData)
      );
      if (item && newData.checked) {
        item.checked = newData.checked;
        setScanTypeDevice(item);
      }
    });
    barcodeInfo.wrongScannedBarcodeList.forEach((barcode) => {
      updateMisScannedCount(barcode);
    });

    inspectionSendAction();
    playSuccessSound();
  }

  const handleItemClickAction = (activeLine, data) => {
    const row = upScanList.value.rows[activeLine];
    if (!row) {
      return;
    }

    const selectableGroupItems = getGroupItems(row).filter((item) => isSelectableItem(item));
    selectableGroupItems.forEach((item) => {
      item.checked = row.checked;
      if (item.checked) {
        setScanTypeManual(item);
      } else {
        clearScanType(item);
      }
    });

    syncRowCheckedState(row);
  };

  function getCameraScanChecked(info) {
    if (isCancelMode()) {
      return info.checked || !isCancelSelectableItem(info);
    }

    return info.checked || !isLoadingSelectableItem(info);
  }

  function getSubmitItems() {
    return agntAllProductList.filter((item) => item.checked && isSelectableItem(item));
  }

  function addMisScannedBarcode(barcodeArray) {
    if (isCancelMode()) {
      return;
    }

    barcodeArray.push(
      ...misScanned.value
        .filter((item) => !item.completed)
        .map((item) => {
          item.completed = true;
          return getScannedBarcode(item);
        })
    );
  }

  function updateRowCheckedByAllCheck() {
    (upScanList.value.rows || []).forEach((row) => {
      syncRowCheckedState(row);
    });
  }

  function updateAllSelectableItems(allCheck) {
    agntAllProductList
      .filter((item) => isSelectableItem(item))
      .forEach((item) => {
        item.checked = allCheck;
        if (allCheck) {
          setScanTypeManual(item);
        } else {
          clearScanType(item);
        }
      });
  }

  function cameraScanAction(type) {
    const list = [];
    agntAllProductList.forEach((info) => {
      list.push({
        checked: getCameraScanChecked(info),
        barcode: info.barcode,
      });
    });

    if (import.meta.env.VITE_COMPILE_MODE !== "LOC") {
      M.execute("exWNStartBarcodeScan", list, scanType.value);
    }
  }

  // 제약 간편검수 전용 거래처 팝업 표시
  function customerInspectionListPopup(index, key, data) {
    customerInspectionBottomSheet.value.title = data.agntName;
    agntProductDetailList.value.rows = agntAllProductList.filter(
      (item) => item.stopCode == data.stopCode && item.loadKey == data.loadKey
    );
    customerInspectionBottomSheet.value.popupState = true;
  }

  function customerInspectionListCloseAction() {
    customerInspectionBottomSheet.value.popupState = false;
  }

  const handleallCheckAction = (allCheck) => {
    updateAllSelectableItems(allCheck);
    updateRowCheckedByAllCheck();
  };

  async function selectScanBarcode(requestFn, reqData) {
    try {
      const response = await requestFn(reqData);
      bindScanBarcodeCntList(response.scanBarcodeList);
      bindScanBarcodeList(response.scanBarcodeCntList);
    } catch (error) {
      console.error(error);
    }
  }

